noncompliant:
using System.ComponentModel;

public void MyMethod([DefaultParameterValue(5)] int j) // Noncompliant
{
  Console.WriteLine(j);
}

compliant:
// Option 1: Use C# default parameter syntax
public void MyMethod(int j = 5)
{
  Console.WriteLine(j);
}

// Option 2: Use both DefaultParameterValue and Optional attributes
using System.ComponentModel;
using System.Runtime.InteropServices;

public void MyMethod([DefaultParameterValue(5)][Optional] int j)
{
  Console.WriteLine(j);
}
